(function(){"use strict";window.Schedule={data:[],container:null,init:function(n,t=[]){(this.container=document.getElementById(n),this.container)&&(this.data=t,this.render(),this.attachEventListeners())},render:function(){let n='<table class="schedule-table"><thead><tr>';const t=this.getScheduleTimes();n+="<th>Час<\/th>";t.forEach(t=>{n+=`<th>${t}</th>`});n+="<\/tr><\/thead><tbody>";this.data.forEach(t=>{n+=`<tr><td>${t.name}</td>`,t.items.forEach(t=>{n+=t?`<td><div class="lesson-item" data-id="${t.id}">
                            <p class="lesson-name">${t.name}</p>
                            <div class="lesson-details">
                                <div class="lesson-teacher">${t.teacher||"N/A"}</div>
                                <div class="lesson-room">${t.room||"N/A"}</div>
                            </div>
                        </div></td>`:"<td><\/td>"}),n+="<\/tr>"});n+="<\/tbody><\/table>";this.container.innerHTML=n},getScheduleTimes:function(){const n=[];for(let t=8;t<18;t++)n.push(`${t}:00 - ${t+1}:00`);return n},attachEventListeners:function(){this.container.querySelectorAll(".lesson-item").forEach(n=>{n.addEventListener("click",()=>{const t=n.dataset.id;this.selectLesson(t)})})},selectLesson:function(n){this.container.querySelectorAll(".lesson-item").forEach(n=>{n.classList.remove("selected")});const t=this.container.querySelector(`[data-id="${n}"]`);t&&t.classList.add("selected")}};console.log("StudentHelper schedule.js initialized")})();